// 1. setTimeout: Bir dəfəlik tapşırıq
function checkCampsite() {
  console.log("Dayanacaq yoxlanılır...");
}

let timeoutId = setTimeout(checkCampsite, 3000);
// nəticə: (3 saniyə sonra) Dayanacaq yoxlanılır...

// Taymeri ləğv etmək
clearTimeout(timeoutId);
// nəticə: Əgər ləğv edilibsə, heç nə baş vermir

// 2. setInterval: Təkrarlanan tapşırıq
function updateMap() {
  console.log("Xəritə yenilənir...");
}

let intervalId = setInterval(updateMap, 4000);
// nəticə: Hər 4 saniyədən bir: Xəritə yenilənir...

// Intervalı dayandırmaq
setTimeout(() => clearInterval(intervalId), 12000);
// nəticə: 12 saniyədən sonra interval dayanır

// 3. Praktik nümunə: Gəzinti xəbərdarlığı
function sendHikeReminder(task, delay) {
  setTimeout(() => {
    console.log(`Xəbərdarlıq: ${task}`);
  }, delay);
}

sendHikeReminder("Suya yaxınlaşmayın!", 2000);
// nəticə: (2 saniyə sonra) Xəbərdarlıq: Suya yaxınlaşmayın!

// 4. Təkrarlanan xəbərdarlıq
function sendWeatherUpdate() {
  console.log("Hava vəziyyəti: Günəşli, ehtiyatlı olun!");
}

let weatherInterval = setInterval(sendWeatherUpdate, 5000);
// nəticə: Hər 5 saniyədən bir: Hava vəziyyəti: Günəşli, ehtiyatlı olun!

// Təhlükə nümunəsi: Dayandırılmamış interval
let warningInterval = setInterval(() => {
  console.log("Xəbərdarlıq: Qrupu yoxlayın!");
}, 2000);
// nəticə: Sonsuz təkrarlanır, dayandırmaq lazımdır

// Düzgün idarəetmə
let hikeReminder = setTimeout(() => {
  console.log("Gəzinti bitdi, qayıdış vaxtıdır!");
}, 5000);

// Ləğv etmək
clearTimeout(hikeReminder);
// nəticə: Əgər ləğv edilibsə, xəbərdarlıq görünməyəcək

// Praktik nümunə: Məhdud sayda təkrar
let count = 0;
let checkInterval = setInterval(() => {
  console.log("Yol yoxlanılır...");
  count++;
  if (count === 3) {
    clearInterval(checkInterval);
    console.log("Yoxlama tamamlandı!");
  }
}, 3000);
// nəticə: 3 dəfə yoxlama, sonra dayanır

