// 1. setTimeout: One-time task
function checkCampsite() {
  console.log("Checking campsite...");
}

let timeoutId = setTimeout(checkCampsite, 3000);
// Output: (3 seconds later) Checking campsite...

// Cancel the timer
clearTimeout(timeoutId);
// Output: If canceled, nothing happens

// 2. setInterval: Repeating task
function updateMap() {
  console.log("Updating map...");
}

let intervalId = setInterval(updateMap, 4000);
// Output: Every 4 seconds: Updating map...

// Stop the interval
setTimeout(() => clearInterval(intervalId), 12000);
// Output: Stops after 12 seconds

// 3. Practical example: Hike reminder
function sendHikeReminder(task, delay) {
  setTimeout(() => {
    console.log(`Reminder: ${task}`);
  }, delay);
}

sendHikeReminder("Stay away from the river!", 2000);
// Output: (2 seconds later) Reminder: Stay away from the river!

// 4. Repeating reminder
function sendWeatherUpdate() {
  console.log("Weather update: Sunny, stay cautious!");
}

let weatherInterval = setInterval(sendWeatherUpdate, 5000);
// Output: Every 5 seconds: Weather update: Sunny, stay cautious!

// Danger example: Unstopped interval
let warningInterval = setInterval(() => {
  console.log("Reminder: Check the group!");
}, 2000);
// Output: Repeats indefinitely unless stopped

// Proper management
let hikeReminder = setTimeout(() => {
  console.log("Hike ended, time to return!");
}, 5000);

// Cancel the timer
clearTimeout(hikeReminder);
// Output: If canceled, no reminder appears

// Practical example: Limited repetitions
let count = 0;
let checkInterval = setInterval(() => {
  console.log("Checking path...");
  count++;
  if (count === 3) {
    clearInterval(checkInterval);
    console.log("Path check completed!");
  }
}, 3000);
// Output: Checks 3 times, then stops

