clearTimeout(timeoutId);
// Вывод: Если отменено, ничего не происходит

// 2. setInterval: Повторяющаяся задача
function updateMap() {
  console.log("Обновление карты...");
}

let intervalId = setInterval(updateMap, 4000);
// Вывод: Каждые 4 секунды: Обновление карты...

// Остановка интервала
setTimeout(() => clearInterval(intervalId), 12000);
// Вывод: Останавливается через 12 секунд

// 3. Практический пример: Напоминание о походе
function sendHikeReminder(task, delay) {
  setTimeout(() => {
    console.log(`Напоминание: ${task}`);
  }, delay);
}

sendHikeReminder("Держитесь подальше от реки!", 2000);
// Вывод: (через 2 секунды) Напоминание: Держитесь подальше от реки!

