let hikeReminder = setTimeout(() => {
  console.log("Поход завершён, пора возвращаться!");
}, 5000);

// Отмена таймера
clearTimeout(hikeReminder);
// Вывод: Если отменено, напоминание не появится

// Практический пример: Ограниченные повторения
let count = 0;
let checkInterval = setInterval(() => {
  console.log("Проверка пути...");
